$(document).ready(()=>{xcalendarDefaultNotifications.initialize()});const xcalendarDefaultNotifications=new function(){this.initialize=()=>{this.onTypeChange(),$("#xcalendar_default_notification_type").on("change",()=>{this.onTypeChange()})},this.onTypeChange=()=>{$("#xcalendar_default_notification_position, #xcalendar_default_notification_number, #xcalendar_default_notification_units").parents("tr").toggle($("#xcalendar_default_notification_type").val()!="none")}},xcalendarCategories=new function(){this.index=1e4,this.add=()=>{const e=$("#xcalendar-categories .category-add input[type=text]"),t=e.val();if(!t)return;$("<div>").append($("<input>").attr("type","text").attr("name","categories["+this.index+"][name]").addClass("form-control").val(t)).append(" ").append($("<input>").attr("type","color").attr("name","categories["+this.index+"][color]").addClass("form-control").val("#87CEFA")).append(" ").append($("<input>").attr("type","button").attr("onclick","$(this).parent().remove()").addClass("button btn btn-sm btn-secondary").val("X")).addClass("category-item").appendTo("#xcalendar-categories .category-list"),e.val(""),this.index++}}